var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"검은 범람 발생 8시간 경과","JPN":"黒い氾濫の発生から8時間経過","ENG":"8 hours since the Black Flood onset","TWN":"黑色洪災發生8小時後"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"아네모네 펀─치!","JPN":"アネモネパ～ンチ！","ENG":"Anemone Puuunch!","TWN":"銀蓮花─拳！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"으아아~ 끝이 없슴다!","JPN":"わわっ～キリがないっす！","ENG":"Whoa...! They just keep coming!","TWN":"嗚啊啊～真是沒完沒了啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"이대로라면 침식체들이 우리 마을을 몽땅 차지할 검다!","JPN":"このままだと侵食体が村を完全に占領しちゃうっす！","ENG":"At this rate, C.O.s are gonna take over our whole village!","TWN":"再這樣下去，侵蝕體會奪走我們整個村子！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"알고 있습니다. 모네.","JPN":"わかっています、モネ。","ENG":"I know, Mone.","TWN":"我知道，莫妮。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이대로라면 저희를 친절하게 받아주신 마을은 물론…….","JPN":"このままでは、私たちを温かく受け入れてくださった村はもちろん……","ENG":"If this keeps up, not only the village that welcomed us so kindly...","TWN":"這樣下去，不只親切接受我們的村子……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이 섬까지 끔살나게 되겠죠.","JPN":"この島までグッバイです。","ENG":"This whole island's gonna get wiped out.","TWN":"連這座島也會被吞沒吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스. 관리국에 지원 요청을 보낸 건 맞습니까?","JPN":"リコリス。確かに管理局に支援を要請したのですか？","ENG":"Lycoris. You did send a support request to the Administration, right?","TWN":"莉克麗絲，妳有向管理局發出支援請求吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"이러다간… 할머니가 되어버려요?","JPN":"このままじゃ……おばあさんになっちゃいますよ？","ENG":"At this rate... we'll turn into grandmas, you know?","TWN":"照這樣下去……我都要變成老婆婆了？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L25_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"당연히 했지!","JPN":"そりゃとっくにしたって！","ENG":"Of course I did!","TWN":"當然有啊！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"하지만 그쪽도 사정이 안 좋은 것 같아.","JPN":"でも、あっちも状況がよくないみたいよ。","ENG":"But things look bad on their side too.","TWN":"可是那邊好像也自身難保。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"검은 범람이 발생해서 도시 전역이 난리라더라.","JPN":"黒い氾濫が発生して、都市全域がめちゃくちゃらしくて。","ENG":"The Black Flood hit, and the whole city's in chaos.","TWN":"黑色洪災爆發，整個城市都亂成一團了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"어쩌면… 이 섬을 포기해야 할지도…….","JPN":"もしかしたら……この島は放棄しないとダメかも……","ENG":"We might... have to abandon this island...","TWN":"搞不好……我們得放棄這座島了……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"꺅?!","JPN":"きゃっ！？","ENG":"Kyaah?!","TWN":"啊？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"야! 왜 때려?!","JPN":"ちょっと！　なんで叩くのよ！","ENG":"Hey! Why'd you hit me?!","TWN":"喂！你幹嘛打我？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"맞을 만하니까 때린 겁니다.","JPN":"叩かれて当然です。","ENG":"Because you deserved it.","TWN":"因為妳活該被打。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스, 이곳은 모네가 나고 자란 고향입니다.","JPN":"リコリス、ここはモネが生まれ育った故郷です。","ENG":"Lycoris, this is Mone's hometown.","TWN":"莉克麗絲，這裡是莫妮出生、長大的故鄉。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그리고 편찮으신 메이드장님을 반갑게 받아주신 분들이 계신 곳이기도 하죠.","JPN":"それに、具合が悪いメイド長を喜んで受け入れてくださった方々がいる場所でもあります。","ENG":"And it's where the people who kindly welcomed our ailing Chief Maid live.","TWN":"也是那些好心接納身體欠安的女僕長的居民們所在之處。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그런 섬을 포기하고 도망가자고요?","JPN":"そんな島を放棄して、逃げようと言うのですか？","ENG":"And you want us to abandon it and run?","TWN":"妳要說放棄這座島、跟大家一起逃跑？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"돌아가면 메이드장님한테 다 이를 겁니다.","JPN":"帰ったらメイド長に全部いいつけます。","ENG":"If we go back, I'll be reporting everything to the Chief Maid.","TWN":"我回去一定會告訴女僕長。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"나, 나도 버리고 싶어서 그러는 줄 알아?!","JPN":"わ、私だって捨てたくてそう言ってるわけじゃないわよ！","ENG":"D-did you think I want to abandon it?!","TWN":"我、我又不是想丟下大家才這麼說的！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"여기서 싸울 수 있는 사람들을 다 그러모아도 힘들잖아.","JPN":"ここで戦える人を全員かき集めたって無理そうだから。","ENG":"Even if we gather everyone who can fight, it's still too much.","TWN":"就算集合所有能戰鬥的人，還是很吃力啊。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"개죽음당하느니, 사람이라도 다 살리는 선택을 하자는 거야.","JPN":"犬死にするくらいなら、人命だけでも救う選択をしようって言ってるの。","ENG":"Choosing to save people instead of dying stupidly?","TWN":"與其白白送死，不如讓更多人活下來。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"그, 그, 그건 모네가 허락할 수 없슴다!","JPN":"そ、そ、それはモネが許さないっす！","ENG":"M-M-Mone can't allow that!","TWN":"莫、莫、莫妮不能接受那種事！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네는 이 섬도 구하고 싶슴다!","JPN":"モネはこの島も救いたいっす！","ENG":"Mone wants to save this island too!","TWN":"莫妮想拯救這座島！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"부모님과 이쁜 추억이 있는 고향을 이대로 넘겨줄 수는 없슴다!","JPN":"両親との思い出が残る故郷を、このまま渡すわけにはいかないっす！","ENG":"I can't just give up the home full of precious memories with my parents!","TWN":"這是有爸媽和珍貴回憶的故鄉，我不想拱手讓出去！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"모네가 더 열심히 싸우겠슴다. 그러니까 포기하면 안됨다!","JPN":"モネがもっと頑張って戦うっす。だから諦めちゃダメっす！","ENG":"Mone will fight even harder! So we can't give up!","TWN":"莫妮會更努力戰鬥，所以不能放棄！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"나 참, 애 앞에선 말도 못 하겠다니까…….","JPN":"もう、子どもの前ではまともに話もできないわね……","ENG":"Ugh... kids make it impossible to say anything...","TWN":"唉，在孩子面前連話都不能說了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"리코리스가 너무 꼰대 같은 마인드를 가지고 있는 거겠죠.","JPN":"根性なしのリコリスが悪いのです。","ENG":"Lycoris is just being a boomer, that's all.","TWN":"是莉克麗絲太老古板吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L2_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저기, 다음 침식체가 옵니다.","JPN":"あそこ、次の侵食体が来ています。","ENG":"C.O. incoming.","TWN":"好了，下一批侵蝕體過來了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"조금 거대하군요.","JPN":"わりと巨大ですね。","ENG":"It's rather big.","TWN":"還挺大的呢。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"마치… 수송기 같은…….","JPN":"まるで……輸送機のような……","ENG":"Almost like... a transport aircraft...","TWN":"就像是……運輸機……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"비행기임다!","JPN":"飛行機っす！","ENG":"It's a plane!","TWN":"是飛機耶！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"관리국에서 지원을 나온 거 아님까?!","JPN":"管理局からの支援じゃないっすか！？","ENG":"That means the Administration came to help, right?!","TWN":"難道是管理局派來支援的嗎？！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"저, 정말 와줬어…….","JPN":"ほ、本当に来てくれたわ……","ENG":"Th-they really came...","TWN":"他、他們真的來了……"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"역시 관리국은 아직 포기하지 않은 거라고!","JPN":"やっぱり管理局はまだ諦めていないのよ！","ENG":"See? The Administration hasn't given up!","TWN":"果然管理局沒有放棄我們！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L13_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"수송기에서 사람이 내립니다.","JPN":"輸送機から人が降りてきます。","ENG":"Someone's getting off the transport aircraft.","TWN":"有人從運輸機上跳下來了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"전원, 지원 병력이 안전하게 내릴 수 있도록 호위합니다!","JPN":"全員、支援兵力が安全に降りられるように援護します！","ENG":"Everyone, protect the landing zone so the support unit can disembark safely!","TWN":"全員，護衛支援兵安全著陸！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"아니, 다짜고짜 뛰어내리라고 하면 어떡해?","JPN":"いや、いきなり飛び降りろってひどくない？","ENG":"Hey, how can you just tell me to jump out like that?!","TWN":"怎麼可以隨便就要人跳下來？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"출력 제한을 어느 정도 풀어줬으니까요.","JPN":"出力制限をある程度緩和しましたから。","ENG":"I eased some of your output limit.","TWN":"因為我稍微解除了妳的輸出限制。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L23_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"당신 능력이라면 이런 식으로 공격하는 게 낫다고 판단했을 뿐이에요.","JPN":"あなたの能力ならこのように攻撃した方がいいと判断したまでです。","ENG":"Based on your capabilities, this was simply the optimal attack vector.","TWN":"以妳的能力，這種方式攻擊反而更有效率。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 밑에 사람이라도 있었으면 어쩌려고?","JPN":"この下に人がいたらどうするんだよ？","ENG":"What if someone was standing down there?!","TWN":"要是下面有人怎麼辦？！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"프론트 베이 도시를 발칵 뒤집은 범죄자가 할 말은 아닌 것 같네요.","JPN":"フロントベイを騒がせた犯罪者のセリフとは思えませんね。","ENG":"Says the criminal who turned Front Bay upside down.","TWN":"一個把前灣搞得天翻地覆的罪犯好像沒資格說這話吧。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그리고 미리 다 확인하고 말한 거거든요?","JPN":"それに、あらかじめ確認もせずに言うわけないでしょう？","ENG":"And I checked beforehand, you know?","TWN":"而且我早就確認過了。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이 깡통이 말하는 것마다 꼬투리를 잡고는……!","JPN":"このポンコツ、いちいち揚げ足取りやがって……！","ENG":"This tin can just nitpicks everything I say...!","TWN":"妳這鐵桶真是張嘴就惹人生氣……"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"여러분의 지원에 감사드립니다.","JPN":"皆さんの支援に感謝します。","ENG":"Thank you for coming to assist us.","TWN":"感謝各位的支援。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"저는 플로라 메이드 서비스의 임시 메이드장을 맡고 있는 릴리라고 합니다.","JPN":"私はフローラメイドサービスの臨時メイド長、リリーと申します。","ENG":"I'm Lily, acting Chief Maid of Flora Maid Service.","TWN":"我是代理的芙蘿拉女僕服務公司的臨時女僕長，莉莉。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"뭐야? 당신 혼자 지원 온 거야?","JPN":"何よ？　あんた1人で支援に来たの？","ENG":"What? You came alone?","TWN":"什麼？妳一個人來支援？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L38_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"리코리스! 기껏 지원 와주신 분 앞에서 너무함다!","JPN":"リコリス！　せっかく支援に来てくれた方の前で失礼っす！","ENG":"Lycoris! Don't be rude to someone who came to help us!","TWN":"莉克麗絲！人家好不容易來這裡，妳不要這麼沒禮貌！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아니! 내가 말만 하면 뭐라 해!","JPN":"ちょっと！　なんで私だけ！？","ENG":"See?! She complains no matter what I say!","TWN":"奇怪！為什麼我說什麼都要念我！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"여기 상황도 심상치 않은데, 혼자 와서 뭘 어쩌겠냐는 거잖아!","JPN":"こっちの状況だって尋常じゃないのに、1人で来てどうするつもりなのかって聞いただけじゃない！","ENG":"I mean, what can one person do in a situation like this?!","TWN":"我只是想說這裡這情況這麼糟，她一個人能怎麼處理啦？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L41_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"평범한 카운터 하나로는 저 침식체들을 막을 수 없다고!","JPN":"普通のカウンター1人で、あの数の侵食体を食い止めるなんてできっこないし！","ENG":"An ordinary Counter can't stop those C.O.s!","TWN":"普通的制裁者根本擋不住那些侵蝕體吧！"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_HATE"},"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L43_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그렇다면 다행이네요.","JPN":"それなら良かったです。","ENG":"Then that's good news.","TWN":"那就太好了。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"응? 왜?","JPN":"えっ？　どうして？","ENG":"Huh? Why?","TWN":"嗯？為什麼？"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"이 사람은 평범한 카운터 하나가 아니거든요.","JPN":"この人は普通のカウンター1人ではありませんから。","ENG":"Because she's not a normal Counter.","TWN":"因為她可不是普通的制裁者。"},"stage":{"bg":"SKY","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_PRIDE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"우, 우와아… 저 언니, 작살 한 방에 침식체가 가버렸슴다.","JPN":"う、うわあ……あのお姉さんの銛の一撃で侵食体がきれいに消えちゃったっす。","ENG":"W-whoa... she just vaporized a C.O. with one harpoon shot.","TWN":"哇、哇啊……那位姊姊一槍就打倒侵蝕體了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"저러면 희망이 있슴다!","JPN":"これなら希望があるっす！","ENG":"Then we have hope!","TWN":"這樣就有希望了！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"TONFA_MAID_NULL_NULL","text":{"KOREA":"릴리 선배! 리코리스! 힘내지 말임다!","JPN":"リリー先輩！　リコリス！　頑張っるっす！","ENG":"Lily! Lycoris! Let's gooo!","TWN":"莉莉前輩！莉克麗絲！加油！"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TONFA_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"좋아요, 모네.","JPN":"そうですね、モネ。","ENG":"All right, Mone.","TWN":"好，莫妮。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그럼 조금만 더 힘내 볼까요?","JPN":"じゃあ、もう少し頑張ってみましょうか。","ENG":"Shall we push a little harder?","TWN":"那我們再努力一下吧？"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"누구누구씨도 좀 더 힘내주면 좋을 텐데 말이에요.","JPN":"誰かさんにももっと頑張ってほしいのですが。","ENG":"You-know-who should push a little harder too, if you ask me.","TWN":"要是某人也能再加把勁就更好了。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPEAR_MAID_NULL_NULL","text":{"KOREA":"아, 알았어. 알았다고.","JPN":"わ、わかった。わかったわよ。","ENG":"O-okay, okay...","TWN":"好啦，我知道了啦。"},"stage":{"bg":"SUMMER_BEACH","bgm":"BATTLE_NORMAL_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"그럼 플로라 메이드.","JPN":"それでは、フローラメイド。","ENG":"Then, Flora Maid.","TWN":"那麼芙蘿拉女僕。"},"stage":{"bg":"SUMMER_BEACH","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPEAR_MAID_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"MASK_MAID_NULL_NULL","text":{"KOREA":"봉사를 시작하겠습니다.","JPN":"ご奉仕を始めます。","ENG":"Will begin our service.","TWN":"開始提供服務吧。"},"stage":{"bg":"SUMMER_BEACH","bgm":"THEMA_FLORA_MAID_SERVICE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MASK_MAID_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};